        "근거수준": "confirmed"
      }
    ],
    "내부스트레치골": [
      {
        "항목": "수요일 릴리스 제안",
        "내용": "수요일 릴리스는 내부 스트레치 골일 뿐, 확정된 공개 릴리스 일정은 아니다.",
        "근거수준": "confirmed"
      }
    ],
    "비결정사항": [
      {
        "항목": "README 설치 단계 검토",
        "내용": "목요일까지 가능하면 검토하자는 언급은 있었으나 담당자가 지정되지 않았다.",
        "근거수준": "partial"
      },
      {
        "항목": "Hara의 tarball path 확인 시점",
        "내용": "Minjun의 스모크 결과 공유 이후 확인하기로 했으나 정확한 마감 시각은 정해지지 않았다.",
        "근거수준": "confirmed"
      }
    ],
    "리스크": [
      {
        "항목": "tarball 경로 오류",
        "영향": "릴리스 지연 가능성",
        "근거수준": "confirmed"
      },
      {
        "항목": "README 설치 단계 최신성 부족",
